<?php
namespace App\Http\Controllers\Api;
use App\Http\Controllers\Controller;use Illuminate\Http\Request;use App\Services\{AuthService,UserService,CategoryService,CulinaryPlaceService,ReviewService,ReservationService,NotificationService};
class ReservationController extends Controller{public function index(Request $r){return $r->user()->reservations()->with('culinaryPlace')->paginate();} public function store(Request $r,ReservationService $s){$data=$r->validate(['culinary_place_id'=>'required|exists:culinary_places,id','reservation_date'=>'required|date','reservation_time'=>'required','guest_count'=>'required|integer|min:1','note'=>'nullable']);$data['user_id']=$r->user()->id;return response()->json($s->create($data),201);} public function update(Request $r,\App\Models\Reservation $reservation){$this->authorize('update',$reservation);$reservation->update($r->all());return $reservation;} public function destroy(\App\Models\Reservation $reservation,ReservationService $s){$this->authorize('delete',$reservation);return $s->transition($reservation->id,'cancelled',auth()->id());} public function confirm(Request $r,ReservationService $s){return $s->transition($r->integer('reservation_id'),'confirmed',$r->user()->id);} public function reject(Request $r,ReservationService $s){return $s->transition($r->integer('reservation_id'),'rejected',$r->user()->id);}}
